// ============================================================
// Transform & Normalize Social Media Data
// Converts all platform API responses into a unified format
// sorted by engagement rate for AI analysis
// ============================================================

const allItems = $input.all();
const normalizedPosts = [];

for (const item of allItems) {
  const d = item.json;
  const platform = d._platform;
  if (!platform) continue;

  switch (platform) {

    case 'twitter': {
      const tweets = d.data || [];
      for (const t of tweets) {
        const m = t.public_metrics || {};
        const interactions = (m.like_count || 0) + (m.reply_count || 0) + (m.retweet_count || 0) + (m.quote_count || 0);
        const impressions = Math.max(m.impression_count || 0, 1);
        normalizedPosts.push({
          platform: 'twitter',
          id: t.id,
          content: t.text || '',
          hook: (t.text || '').split('\n')[0].substring(0, 200),
          created_at: t.created_at,
          likes: m.like_count || 0,
          comments: m.reply_count || 0,
          shares: (m.retweet_count || 0) + (m.quote_count || 0),
          views: m.impression_count || 0,
          engagement_rate: parseFloat(((interactions / impressions) * 100).toFixed(4)),
          url: `https://twitter.com/i/web/status/${t.id}`,
          format: (t.text || '').length > 280 ? 'thread' : 'tweet'
        });
      }
      break;
    }

    case 'instagram': {
      const posts = d.data || [];
      for (const p of posts) {
        const likes = p.like_count || 0;
        const comments = p.comments_count || 0;
        // Instagram doesn't always return impressions in basic fields
        // Use a conservative estimate of 10x engagement as a fallback
        const impressions = Math.max(likes * 10 + comments * 5, 1);
        normalizedPosts.push({
          platform: 'instagram',
          id: p.id,
          content: p.caption || '',
          hook: (p.caption || '').split('\n')[0].substring(0, 200),
          created_at: p.timestamp,
          likes,
          comments,
          shares: 0,
          views: impressions,
          engagement_rate: parseFloat((((likes + comments) / impressions) * 100).toFixed(4)),
          url: p.permalink || '',
          format: p.media_type === 'VIDEO' ? 'reel'
            : p.media_type === 'CAROUSEL_ALBUM' ? 'carousel'
            : 'image'
        });
      }
      break;
    }

    case 'tiktok': {
      const videos = (d.data && d.data.videos) ? d.data.videos : (d.data || []);
      for (const v of videos) {
        const likes = v.like_count || 0;
        const comments = v.comment_count || 0;
        const shares = v.share_count || 0;
        const views = Math.max(v.view_count || 0, 1);
        normalizedPosts.push({
          platform: 'tiktok',
          id: v.id,
          content: v.video_description || v.title || '',
          hook: (v.video_description || v.title || '').split('\n')[0].substring(0, 200),
          created_at: new Date((v.create_time || 0) * 1000).toISOString(),
          likes,
          comments,
          shares,
          views,
          engagement_rate: parseFloat((((likes + comments + shares) / views) * 100).toFixed(4)),
          url: v.share_url || '',
          format: 'video'
        });
      }
      break;
    }

    case 'linkedin': {
      const posts = d.elements || [];
      for (const p of posts) {
        const shareContent = p.specificContent?.['com.linkedin.ugc.ShareContent'] || {};
        const body = shareContent.shareCommentary?.text || '';
        const stats = p.socialDetail?.totalSocialActivityCounts || {};
        const likes = stats.numLikes || 0;
        const comments = stats.numComments || 0;
        const impressions = Math.max(stats.numImpressions || 0, 1);
        normalizedPosts.push({
          platform: 'linkedin',
          id: p.id,
          content: body,
          hook: body.split('\n')[0].substring(0, 200),
          created_at: new Date(p.created?.time || 0).toISOString(),
          likes,
          comments,
          shares: stats.numShares || 0,
          views: impressions,
          engagement_rate: parseFloat((((likes + comments) / impressions) * 100).toFixed(4)),
          url: `https://www.linkedin.com/feed/update/${p.id}`,
          format: shareContent.shareMediaCategory === 'VIDEO' ? 'video'
            : shareContent.shareMediaCategory === 'IMAGE' ? 'image'
            : 'post'
        });
      }
      break;
    }

    case 'youtube': {
      const videos = d.items || [];
      for (const v of videos) {
        const stats = v.statistics || {};
        const likes = parseInt(stats.likeCount || 0);
        const comments = parseInt(stats.commentCount || 0);
        const views = Math.max(parseInt(stats.viewCount || 0), 1);
        const title = v.snippet?.title || '';
        const description = (v.snippet?.description || '').substring(0, 500);
        normalizedPosts.push({
          platform: 'youtube',
          id: v.id?.videoId || (typeof v.id === 'string' ? v.id : ''),
          content: `${title}\n\n${description}`,
          hook: title,
          created_at: v.snippet?.publishedAt,
          likes,
          comments,
          shares: 0,
          views,
          engagement_rate: parseFloat((((likes + comments) / views) * 100).toFixed(4)),
          url: `https://youtube.com/watch?v=${v.id?.videoId || v.id}`,
          format: 'video'
        });
      }
      break;
    }
  }
}

// Sort by engagement rate descending — top performers first
normalizedPosts.sort((a, b) => b.engagement_rate - a.engagement_rate);

// Build platform breakdown summary
const platformCounts = normalizedPosts.reduce((acc, p) => {
  acc[p.platform] = (acc[p.platform] || 0) + 1;
  return acc;
}, {});

// Select top 25 for AI analysis (keeps Claude prompt lean)
const top25 = normalizedPosts.slice(0, 25);

console.log(`Normalized ${normalizedPosts.length} posts across ${Object.keys(platformCounts).length} platforms`);

return [{
  json: {
    posts: normalizedPosts,
    top25,
    total: normalizedPosts.length,
    platformCounts,
    generatedAt: new Date().toISOString()
  }
}];

// Build the Anthropic API request body for performance analysis.
// Sends top 25 posts + creator context to Claude for deep pattern extraction.

const data = $input.first().json;
const cfg = $('⚙️ Config').first().json;
const top25 = data.top25 || [];

// Slim the post data to just what the model needs (saves tokens)
const postsForAnalysis = top25.map(p => ({
  platform: p.platform,
  hook: p.hook,
  format: p.format,
  engagement_rate_pct: p.engagement_rate,
  likes: p.likes,
  comments: p.comments,
  shares: p.shares,
  views: p.views
}));

const prompt = `You are a world-class content strategist and copywriter who specializes in viral social media growth.

CREATOR CONTEXT
- Niche: ${cfg.niche}
- Target Audience: ${cfg.targetAudience}
- Primary Goal: ${cfg.contentGoal}
- Total Posts Analyzed: ${data.total}
- Platform Breakdown: ${JSON.stringify(data.platformCounts)}

TOP ${top25.length} POSTS BY ENGAGEMENT RATE:
${JSON.stringify(postsForAnalysis, null, 2)}

Analyze these posts and return a JSON object with EXACTLY this structure. Be specific and data-driven — cite actual hooks and patterns from the data:

{
  "top_hook_patterns": [
    {
      "pattern_name": "e.g. The Uncomfortable Truth",
      "description": "psychological reason this stops the scroll",
      "example_hooks": ["exact hook 1 from the data", "exact hook 2"],
      "avg_engagement_rate": 0.00,
      "best_platform": "platform name",
      "use_when": "specific trigger for using this hook"
    }
  ],
  "top_content_formats": [
    {
      "format": "thread|carousel|reel|video|post|tweet",
      "why_it_works": "mechanism of engagement",
      "best_example_hook": "top hook using this format",
      "avg_engagement_rate": 0.00,
      "ideal_length": "e.g. 5-7 bullet points, 60-90 second video"
    }
  ],
  "winning_themes": [
    {
      "theme": "theme name",
      "description": "why this resonates with the specific audience",
      "post_count": 0,
      "avg_engagement_rate": 0.00
    }
  ],
  "platform_insights": {
    "twitter": { "what_works": "", "hook_style": "", "optimal_length": "", "posting_tip": "" },
    "instagram": { "what_works": "", "hook_style": "", "optimal_format": "", "posting_tip": "" },
    "tiktok": { "what_works": "", "hook_style": "", "content_style": "", "posting_tip": "" },
    "linkedin": { "what_works": "", "hook_style": "", "tone": "", "posting_tip": "" },
    "youtube": { "what_works": "", "title_pattern": "", "thumbnail_concept": "", "posting_tip": "" }
  },
  "audience_insights": {
    "pain_points_that_drive_engagement": ["string"],
    "desires_that_drive_engagement": ["string"],
    "emotional_triggers": ["string"],
    "language_patterns": ["exact phrases that appear in high-performing hooks"]
  },
  "content_gaps": ["topics your audience likely wants that your top posts haven't covered"],
  "strategic_summary": "3-4 sentences: what's working, why, and the single biggest opportunity to improve performance"
}

Return ONLY the JSON object. No markdown fences, no explanation text outside the JSON.`;

return [{
  json: {
    model: cfg.claudeModel || 'claude-opus-4-6',
    max_tokens: 4096,
    messages: [{ role: 'user', content: prompt }]
  }
}];

// Build the Anthropic API request for content idea generation.
// Combines performance analysis output + all trend research into one prompt.

const cfg = $('⚙️ Config').first().json;
const trendItems = $input.all();

// ---- Parse performance analysis from Claude ----
let analysis = {};
try {
  const analyzeResponse = $('🤖 Analyze Top Performers').first().json;
  const rawText = analyzeResponse.content?.[0]?.text || '';
  // Try direct parse first, then strip markdown fences if needed
  try {
    analysis = JSON.parse(rawText);
  } catch (e1) {
    const match = rawText.match(/```(?:json)?\s*([\s\S]*?)\s*```/) || rawText.match(/\{[\s\S]*\}/);
    analysis = match ? JSON.parse(match[1] || match[0]) : {};
  }
} catch (e) {
  console.log('Could not parse analysis response, continuing with empty analysis');
  analysis = {};
}

// ---- Compile trend research from all 5 sources ----
const trends = {};
for (const item of trendItems) {
  const d = item.json;
  switch (d._source) {
    case 'perplexity':
      trends.perplexity = d.choices?.[0]?.message?.content || '';
      break;
    case 'reddit':
      trends.reddit_hot = (d.data?.children || []).slice(0, 15).map(p => ({
        title: p.data?.title,
        score: p.data?.score,
        subreddit: p.data?.subreddit,
        num_comments: p.data?.num_comments
      }));
      break;
    case 'x_trending':
      trends.x_trending = d.data || [];
      break;
    case 'tiktok_trends':
      trends.tiktok_hashtags = d.data?.hashtags || d;
      break;
    case 'google_trends':
      trends.google_trends = {
        keywords: cfg.googleTrendKeywords,
        timeline: d.interest_over_time?.timeline_data?.slice(-4) || []
      };
      break;
  }
}

const prompt = `You are a world-class content strategist. Using our performance data and current trend research, generate exactly ${cfg.contentIdeasCount || 15} high-potential content ideas.

CREATOR CONTEXT
- Niche: ${cfg.niche}
- Target Audience: ${cfg.targetAudience}
- Content Goal: ${cfg.contentGoal}

WHAT WORKS FOR THIS CREATOR (performance analysis)
${JSON.stringify({
  top_hooks: analysis.top_hook_patterns?.slice(0, 5),
  winning_themes: analysis.winning_themes?.slice(0, 5),
  pain_points: analysis.audience_insights?.pain_points_that_drive_engagement,
  desires: analysis.audience_insights?.desires_that_drive_engagement,
  language_patterns: analysis.audience_insights?.language_patterns,
  content_gaps: analysis.content_gaps,
  summary: analysis.strategic_summary
}, null, 2)}

CURRENT TREND INTELLIGENCE (this week)
${JSON.stringify(trends, null, 2)}

Generate exactly ${cfg.contentIdeasCount || 15} content ideas. For each idea, write the hook as the ACTUAL first sentence/line of the content — not a description of the hook. Return ONLY this JSON object:

{
  "weekly_theme": "string — single overarching theme that connects the best ideas this week",
  "theme_rationale": "string — why this theme is timely and resonant right now",
  "content_ideas": [
    {
      "id": 1,
      "title": "string — compelling title for the content piece",
      "hook": "string — THE ACTUAL FIRST LINE of the content (not a description — write the real hook)",
      "sub_hook": "string — the second sentence that deepens the tension or promise",
      "angle": "string — the unique perspective, contrarian take, or unexpected frame",
      "format": "tweet|thread|carousel|reel|youtube-video|linkedin-post|tiktok-video",
      "primary_platform": "string",
      "secondary_platforms": ["string"],
      "trending_connection": "string — specific trend/data point from our research this taps into",
      "performance_basis": "string — which of our proven patterns this leverages and why it will work",
      "outline": ["string — point 1", "string — point 2", "string — point 3", "string — point 4", "string — point 5"],
      "cta": "string — exact call-to-action text",
      "hook_pattern_used": "string — which top hook pattern from our analysis this uses",
      "potential_score": 8.5,
      "effort_level": "low|medium|high",
      "estimated_time_minutes": 30,
      "tags": ["string"],
      "repurpose_ideas": ["string — how to repurpose across other platforms"]
    }
  ],
  "priority_ideas": [1, 3, 7],
  "quick_wins": [2, 5],
  "batch_recording_sets": [
    {
      "theme": "string — batch session theme",
      "idea_ids": [1, 4, 8],
      "rationale": "string — why these work well to record together"
    }
  ]
}

Return ONLY the JSON object. No markdown fences. No text outside the JSON.`;

return [{
  json: {
    model: cfg.claudeModel || 'claude-opus-4-6',
    max_tokens: 8192,
    messages: [{ role: 'user', content: prompt }]
  }
}];

// Parse Claude's content ideas response and prepare data for Notion
const claudeResponse = $input.first().json;
const cfg = $('⚙️ Config').first().json;
const rawContent = claudeResponse.content?.[0]?.text || '';

let ideasData = {};
try {
  ideasData = JSON.parse(rawContent);
} catch (e) {
  // Try stripping markdown code fences if present
  const match = rawContent.match(/```(?:json)?\s*([\s\S]*?)\s*```/) || rawContent.match(/\{[\s\S]*\}/);
  if (match) {
    try {
      ideasData = JSON.parse(match[1] || match[0]);
    } catch (e2) {
      throw new Error(`Could not parse Claude response as JSON: ${e2.message}\n\nRaw response: ${rawContent.substring(0, 500)}`);
    }
  } else {
    throw new Error('No valid JSON found in Claude response');
  }
}

const now = new Date();
const weekStr = now.toLocaleDateString('en-US', { month: 'long', day: 'numeric', year: 'numeric' });
const ideas = ideasData.content_ideas || [];

// Build platform insights summary from Phase 2 analysis
let analysisSummary = 'See analysis output for details.';
try {
  const analyzeResponse = $('🤖 Analyze Top Performers').first().json;
  const analysisRaw = analyzeResponse.content?.[0]?.text || '';
  const analysisData = JSON.parse(analysisRaw);
  analysisSummary = analysisData.strategic_summary || analysisSummary;
} catch (e) {
  // Non-fatal — use fallback
}

console.log(`Parsed ${ideas.length} content ideas. Weekly theme: ${ideasData.weekly_theme}`);

return [{
  json: {
    reportTitle: `📊 Content Intelligence Report — Week of ${weekStr}`,
    weeklyTheme: ideasData.weekly_theme || 'Content Strategy Week',
    themeRationale: ideasData.theme_rationale || '',
    analysisSummary,
    totalIdeas: ideas.length,
    priorityIdeas: ideasData.priority_ideas || [],
    quickWins: ideasData.quick_wins || [],
    batchSets: ideasData.batch_recording_sets || [],
    generatedAt: now.toISOString(),
    ideas,
    notionDatabaseId: cfg.notionDatabaseId,
    niche: cfg.niche,
    targetAudience: cfg.targetAudience
  }
}];

// Split the ideas array into individual items.
// n8n will run the downstream Notion node once per item,
// creating one child page per content idea.

const reportData = $('📝 Format Notion Report Data').first().json;
const notionResult = $input.first().json;

// The Notion API returns the created page's ID — we need this as the parent
const parentPageId = notionResult.id || '';

if (!parentPageId) {
  throw new Error('No parent page ID returned from Notion. Check Notion credentials and database ID.');
}

const ideas = reportData.ideas || [];
const priorityIds = reportData.priorityIdeas || [];
const quickWinIds = reportData.quickWins || [];

console.log(`Creating ${ideas.length} idea pages as children of page ${parentPageId}`);

// Return one item per idea — each becomes one Notion child page
return ideas.map(idea => ({
  json: {
    parentPageId,
    ...idea,
    isPriority: priorityIds.includes(idea.id),
    isQuickWin: quickWinIds.includes(idea.id),
    weeklyTheme: reportData.weeklyTheme,
    niche: reportData.niche
  }
}));

// Collapse N idea-creation results (one per idea) back into
// a single summary item for the Slack notification.

const items = $input.all();
const cfg = $('⚙️ Config').first().json;
const reportData = $('📝 Format Notion Report Data').first().json;
const parentPage = $('📓 Create Notion Report Page').first().json;

const successfulPages = items.filter(i => i.json.object === 'page' || i.json.id);
const notionUrl = parentPage.url || `https://notion.so/${(parentPage.id || '').replace(/-/g, '')}`;

console.log(`Successfully created ${successfulPages.length}/${items.length} idea pages`);

return [{
  json: {
    success: true,
    reportTitle: reportData.reportTitle,
    weeklyTheme: reportData.weeklyTheme,
    ideasCreated: successfulPages.length,
    ideasRequested: items.length,
    notionUrl,
    generatedAt: new Date().toISOString(),
    slackMessage: `*✅ Weekly Content Intelligence Report Ready*\n\n*Theme:* ${reportData.weeklyTheme}\n*Ideas Created:* ${successfulPages.length}/${items.length}\n*Notion Report:* ${notionUrl}\n\n_Generated ${new Date().toLocaleString()}_`
  }
}];
